class Solution{

  public:
	int minDifference(vector<int>&arr, int n)  {
		int totalSum = 0;
		for(int i = 0; i < n; i++) totalSum += arr[i];

		// dp[s] = true if some subset of arr can sum to s
		vector<char> dp(totalSum + 1, false);
		dp[0] = true;
		for(int i = 0; i < n; i++){
			for(int s = totalSum; s >= arr[i]; s--){
				if(dp[s - arr[i]]) dp[s] = true;
			}
		}

		int ans = INT_MAX;
		for(int s = 0; s <= totalSum / 2; s++){
			if(dp[s]) ans = min(ans, abs((totalSum - s) - s));
		}
		return ans;
	}
};

