        return ans;
    }
};

minimum-multiplications-to-reach-end.code:
class Solution{
public:
    int minimumMultiplications(vector<int> &arr,
                               int start, int end) {
        const int MOD = 100000;
        if (start == end) return 0;
        vector<int> dist(MOD, -1);
        queue<int> q;
        dist[start] = 0;
        q.push(start);
        while (!q.empty()) {
            int node = q.front(); q.pop();
            int steps = dist[node];
            for (int x : arr) {
                int nxt = (int)((long long)node * x % MOD);
                if (dist[nxt] == -1) {
                    dist[nxt] = steps + 1;
                    if (nxt == end) return steps + 1;
                    q.push(nxt);
                }
            }
        }
        return -1;
    }
};

