class Solution {
public:
    void maxHeapify(vector<int>& nums, int i, int n) {
        int largest = i;
        int left = 2 * i + 1;
        int right = 2 * i + 2;
        if (left < n && nums[left] > nums[largest]) largest = left;
        if (right < n && nums[right] > nums[largest]) largest = right;
        if (largest != i) {
            swap(nums[i], nums[largest]);
            maxHeapify(nums, largest, n);
        }
    }
    vector<int> minToMaxHeap(vector<int> nums) {
        int n = (int)nums.size();
        for (int i = n / 2 - 1; i >= 0; i--) {
            maxHeapify(nums, i, n);
        }
        return nums;
    }
};

string-to-integer-atoi-1.code:
class Solution {
public:
    int myAtoi(string input) {
        int n = (int)input.size();
        int i = 0;
        // skip leading whitespace
        while (i < n && input[i] == ' ') i++;
        if (i == n) return 0;
        int sign = 1;
        if (input[i] == '+' || input[i] == '-') {
            if (input[i] == '-') sign = -1;
            i++;
        }
        long long ans = 0;
        while (i < n && input[i] >= '0' && input[i] <= '9') {
            ans = ans * 10 + (input[i] - '0');
            if (sign == 1 && ans > 2147483647LL) return 2147483647;
            if (sign == -1 && -ans < -2147483648LL) return -2147483648;
            i++;
        }
        ans = sign * ans;
        if (ans > 2147483647LL) return 2147483647;
        if (ans < -2147483648LL) return -2147483648;
        return (int)ans;
    }
};

count-partitions-with-given-difference.code:
class Solution {
  public:
   int countPartitions(int n, int diff, vector<int>& arr) {
        const int mod = 1e9 + 7;
        long long totalSum = 0;
        for (int x : arr) totalSum += x;
        // S1 + S2 = totalSum, S1 - S2 = diff  =>  S2 = (totalSum - diff) / 2
        if (totalSum - diff < 0 || (totalSum - diff) % 2 != 0) return 0;
        long long target = (totalSum - diff) / 2;
        // dp[j] = number of subsets (using processed elements) with sum == j
        // Zeros are handled by the base case so an element equal to 0 can be
        // placed in either subset, doubling the count.
        vector<long long> dp(target + 1, 0);
        if (arr[0] == 0) {
            dp[0] = 2; // include or exclude => both yield sum 0
        } else {
            dp[0] = 1;
            if (arr[0] <= target) dp[arr[0]] = (dp[arr[0]] + 1) % mod;
        }
        for (int i = 1; i < n; i++) {
            vector<long long> cur(target + 1, 0);
            for (long long j = 0; j <= target; j++) {
                long long notTake = dp[j];
                long long take = 0;
                if (arr[i] <= j) take = dp[j - arr[i]];
                cur[j] = (notTake + take) % mod;
            }
            dp = cur;
        }
        return (int)(dp[target] % mod);
    }
};

