subset-sum-equals-to-target.code:
class Solution{   
public:
    bool isSubsetSum(vector<int>arr, int target){
        int n = arr.size();
        // dp[s] = can we form sum s using the elements processed so far
        // 0/1 knapsack feasibility; iterate sum downward so each element is used at most once
        vector<char> dp(target + 1, 0);
        dp[0] = 1;
        for (int i = 0; i < n; i++) {
            int v = arr[i];
            if (v < 0) continue; // negative values cannot help reach a non-negative bounded target with this DP
            for (int s = target; s >= v; s--) {
                if (dp[s - v]) dp[s] = 1;
            }
        }
        return dp[target] != 0;
    }
};

