    int totalFruits(vector<int>& fruits){
        int n = fruits.size();
        int left = 0, maxLen = 0;
        unordered_map<int,int> cnt;
        for (int right = 0; right < n; right++) {
            cnt[fruits[right]]++;
            while ((int)cnt.size() > 2) {
                cnt[fruits[left]]--;
                if (cnt[fruits[left]] == 0) cnt.erase(fruits[left]);
                left++;
            }
            maxLen = max(maxLen, right - left + 1);
        }
        return maxLen;
    }
};

