    vector<string> generateParenthesis(int n) {
        vector<string> res;
        string cur;
        function<void(int,int)> rec = [&](int open, int close){
            if((int)cur.size() == 2*n){ res.push_back(cur); return; }
            if(open < n){ cur.push_back('('); rec(open+1, close); cur.pop_back(); }
            if(close < open){ cur.push_back(')'); rec(open, close+1); cur.pop_back(); }
        };
        rec(0,0);
        return res;
    }
};

3-sum.code:
class Solution {
public:
    vector<vector<int>> threeSum(vector<int>& nums) {
        vector<vector<int>> ans;
        sort(nums.begin(), nums.end());
        int n = nums.size();

        for (int k = 0; k < n; k++) {
            if (k > 0 && nums[k] == nums[k - 1]) continue;
            int i = k + 1;
            int j = n - 1;
            int target = -nums[k];
            while (i < j) {
                int sum = nums[i] + nums[j];
                if (sum == target) {
                    ans.push_back({nums[k], nums[i], nums[j]});
                    i++;
                    j--;
                    while (i < j && nums[i] == nums[i - 1]) i++;
                    while (i < j && nums[j] == nums[j + 1]) j--;
                } else if (sum < target) {
                    i++;
                } else {
                    j--;
                }
            }
        }
        return ans;
    }
};

