count-all-subsequences-with-sum-k.code:
class Solution{
    public:    	
    int countSubsequenceWithTargetSum(vector<int>& nums, int k){
        int n = nums.size();
        // dp[i][t] = number of subsequences using first i elements with sum t
        vector<vector<long long>> dp(n+1, vector<long long>(k+1, 0));
        dp[0][0] = 1; // empty subsequence has sum 0
        for(int i = 1; i <= n; i++){
            for(int t = 0; t <= k; t++){
                long long notTake = dp[i-1][t];
                long long take = 0;
                if(nums[i-1] <= t) take = dp[i-1][t - nums[i-1]];
                dp[i][t] = take + notTake;
            }
        }
        // Since k >= 1 per constraints, the empty subsequence (sum 0) is never counted here.
        return (int)dp[n][k];
    }
};

edit-distance.code:
class Solution {
  public:
    int editDistance(string start, string target) {
        int n = start.size(), m = target.size();
        vector<int> prev(m + 1, 0), cur(m + 1, 0);
        for (int j = 0; j <= m; j++) prev[j] = j;
        for (int i = 1; i <= n; i++) {
            cur[0] = i;
            for (int j = 1; j <= m; j++) {
                if (start[i - 1] == target[j - 1]) {
                    cur[j] = prev[j - 1];
                } else {
                    cur[j] = 1 + min({prev[j - 1], prev[j], cur[j - 1]});
                }
            }
            prev = cur;
        }
        return prev[m];
    }
};

