class Solution{
    public:
        vector<vector<int>> primeFactors(vector<int>& queries){
            vector<vector<int>> ans;
            ans.reserve(queries.size());
            for(int q : queries){
                vector<int> factors;
                int x = q;
                for(int d = 2; (long long)d * d <= x; d++){
                    while(x % d == 0){
                        factors.push_back(d);
                        x /= d;
                    }
                }
                if(x > 1) factors.push_back(x);
                ans.push_back(factors);
            }
            return ans;
        }
};

generate-binary-strings-without-consecut.code:
class Solution {
public:
    vector<string> generateBinaryStrings(int n) {
        vector<string> result;
        string cur;
        solve(0, n, cur, result);
        return result;
    }
private:
    void solve(int idx, int n, string &cur, vector<string> &result) {
        if (idx == n) {
            result.push_back(cur);
            return;
        }
        // Place '0' always (tried first to keep lexicographic order)
        cur.push_back('0');
        solve(idx + 1, n, cur, result);
        cur.pop_back();
        // Place '1' only if previous char is not '1'
        if (idx == 0 || cur[idx - 1] != '1') {
            cur.push_back('1');
            solve(idx + 1, n, cur, result);
            cur.pop_back();
        }
    }
};

