class Solution{
	public:
	int perfectSum(vector<int>&arr, int K){
	    const int MOD = 1e9 + 7;
	    int n = (int)arr.size();
	    // dp[j] = number of subsets with sum j (modulo MOD)
	    vector<long long> dp(K + 1, 0);
	    dp[0] = 1; // the empty subset has sum 0
	    for (int i = 0; i < n; i++) {
	        // iterate downwards so each element is used at most once
	        for (int j = K; j >= arr[i]; j--) {
	            dp[j] = (dp[j] + dp[j - arr[i]]) % MOD;
	        }
	    }
	    return (int)(dp[K] % MOD);
	}
};

longest-subarray-with-sum-k.code:
class Solution{
public:
    int longestSubarray(vector<int> &nums, int k){
        unordered_map<long long, int> firstIdx; // prefix sum -> earliest index seen
        long long pref = 0;
        int ans = 0;
        int n = nums.size();
        for (int i = 0; i < n; i++) {
            pref += (long long)nums[i];
            if (pref == (long long)k) {
                ans = max(ans, i + 1);
            }
            long long need = pref - (long long)k;
            auto it = firstIdx.find(need);
            if (it != firstIdx.end()) {
                ans = max(ans, i - it->second);
            }
            if (firstIdx.find(pref) == firstIdx.end()) {
                firstIdx[pref] = i;
            }
        }
        return ans;
    }
};

