    vector<int> bubbleSort(vector<int>& nums) {
        int n = nums.size();
        for (int i = n - 1; i > 0; i--) {
            bool swapped = false;
            for (int j = 0; j < i; j++) {
                if (nums[j] > nums[j + 1]) {
                    swap(nums[j], nums[j + 1]);
                    swapped = true;
                }
            }
            if (!swapped) break;
        }
        return nums;
    }
};

longest-word-with-all-prefixes.code:
class Solution {
public:
    string completeString(vector<string>& nums) {
        struct TrieNode {
            TrieNode* children[26];
            bool end;
            TrieNode() {
                end = false;
                for (int i = 0; i < 26; i++) children[i] = nullptr;
            }
        };
        TrieNode* root = new TrieNode();
        // insert all words into the trie
        for (auto& word : nums) {
            TrieNode* curr = root;
            for (char ch : word) {
                int key = ch - 'a';
                if (curr->children[key] == nullptr)
                    curr->children[key] = new TrieNode();
                curr = curr->children[key];
            }
            curr->end = true;
        }
        // a word is complete if every prefix (including itself) is marked end
        auto isValid = [&](const string& word) -> bool {
            TrieNode* curr = root;
            for (char ch : word) {
                int key = ch - 'a';
                if (curr->children[key] == nullptr || curr->children[key]->end == false)
                    return false;
                curr = curr->children[key];
            }
            return true;
        };
        string ans = "";
        bool found = false;
        for (auto& word : nums) {
            if (isValid(word)) {
                if (!found) { ans = word; found = true; }
                else if (word.size() > ans.size()) ans = word;
                else if (word.size() == ans.size() && word < ans) ans = word;
            }
        }
        if (!found) return "None";
        return ans;
    }
};

