class Solution{
  public:
    int rodCutting(vector<int> price, int n) {
        // price[i] = value of a rod piece of length (i+1), 1-based lengths.
        // n = total rod length; here n == price.size().
        // dp[len] = max value obtainable from a rod of length len.
        vector<long long> dp(n + 1, 0);
        for (int len = 1; len <= n; len++) {
            long long best = LLONG_MIN;
            for (int cut = 1; cut <= len; cut++) {
                best = max(best, (long long)price[cut - 1] + dp[len - cut]);
            }
            dp[len] = best;
        }
        return (int)dp[n];
    }
};

check-if-the-number-if-armstrong.code:
class Solution {
public:
    bool isArmstrong(int n) {
        long long original = n;
        int digits = 0;
        long long temp = n;
        if (temp == 0) {
            digits = 1;
        } else {
            while (temp > 0) {
                digits++;
                temp /= 10;
            }
        }
        long long sum = 0;
        temp = n;
        if (temp == 0) {
            sum = 0;
        } else {
            while (temp > 0) {
                long long d = temp % 10;
                long long p = 1;
                for (int i = 0; i < digits; i++) p *= d;
                sum += p;
                temp /= 10;
            }
        }
        return sum == original;
    }
};

number-of-enclaves.code:
class Solution{
public:
    int numberOfEnclaves(vector<vector<int>> &grid) {
        int n = grid.size();
        if (n == 0) return 0;
        int m = grid[0].size();
        vector<vector<bool>> vis(n, vector<bool>(m, false));
        queue<pair<int,int>> q;
        // push all boundary land cells
        for (int j = 0; j < m; j++) {
            if (grid[0][j] == 1 && !vis[0][j]) { vis[0][j] = true; q.push({0, j}); }
            if (grid[n-1][j] == 1 && !vis[n-1][j]) { vis[n-1][j] = true; q.push({n-1, j}); }
        }
        for (int i = 0; i < n; i++) {
            if (grid[i][0] == 1 && !vis[i][0]) { vis[i][0] = true; q.push({i, 0}); }
            if (grid[i][m-1] == 1 && !vis[i][m-1]) { vis[i][m-1] = true; q.push({i, m-1}); }
        }
        int dr[] = {-1, 0, 1, 0};
        int dc[] = {0, 1, 0, -1};
        while (!q.empty()) {
            auto [r, c] = q.front(); q.pop();
            for (int d = 0; d < 4; d++) {
                int nr = r + dr[d], nc = c + dc[d];
                if (nr >= 0 && nr < n && nc >= 0 && nc < m && !vis[nr][nc] && grid[nr][nc] == 1) {
                    vis[nr][nc] = true;
                    q.push({nr, nc});
                }
            }
        }
        int ans = 0;
        for (int i = 0; i < n; i++)
            for (int j = 0; j < m; j++)
                if (grid[i][j] == 1 && !vis[i][j]) ans++;
        return ans;
    }
};

