class Solution{
public:
    int subarraysWithXorK(vector<int> &nums, int k) {
        unordered_map<int,int> cnt;
        int xr = 0;
        long long ans = 0;
        cnt[0] = 1;
        for (int x : nums) {
            xr ^= x;
            int need = xr ^ k;
            auto it = cnt.find(need);
            if (it != cnt.end()) ans += it->second;
            cnt[xr]++;
        }
        return (int)ans;
    }
};

number-of-distinct-substrings-in-a-strin.code:
class Solution{
    public:
        int countDistinctSubstring(string s){
            int n = s.size();
            // Trie stored as a vector of 26-way nodes; -1 means no child.
            vector<array<int,26>> trie;
            trie.push_back(array<int,26>());
            trie[0].fill(-1);
            int cnt = 0;
            for (int i = 0; i < n; i++) {
                int curr = 0;
                for (int j = i; j < n; j++) {
                    int ltr = s[j] - 'a';
                    if (trie[curr][ltr] == -1) {
                        cnt++;
                        array<int,26> node;
                        node.fill(-1);
                        trie.push_back(node);
                        trie[curr][ltr] = (int)trie.size() - 1;
                    }
                    curr = trie[curr][ltr];
                }
            }
            return cnt + 1; // +1 for the empty substring
        }
};

