requirements-needed-to-construct-a-uniqu.code:
class Solution{	
	public:	
		bool uniqueBinaryTree(int a, int b){
			// Traversal codes: 1 -> Preorder, 2 -> Inorder, 3 -> Postorder.
			// A unique binary tree can be reconstructed from a pair of traversals
			// if and only if exactly one of the two traversals is Inorder (2).
			// Inorder is required to split nodes into left/right subtrees, and
			// pairing it with Preorder or Postorder yields a unique tree.
			// Preorder+Postorder (or any same-type / non-inorder pair) is ambiguous,
			// and two Inorder traversals are also insufficient.
			return (a == 2) ^ (b == 2);
		}
};

