class Solution
{
public:
    int largestRectangleArea(vector<int> &heights){
        int n = heights.size();
        stack<int> st;
        int maxArea = 0;
        for(int i = 0; i <= n; i++){
            int cur = (i == n) ? 0 : heights[i];
            while(!st.empty() && heights[st.top()] >= cur){
                int height = heights[st.top()];
                st.pop();
                int width = st.empty() ? i : (i - st.top() - 1);
                maxArea = max(maxArea, height * width);
            }
            st.push(i);
        }
        return maxArea;
    }
    int maximalAreaOfSubMatrixOfAll1(vector<vector<int>> &matrix){
        if(matrix.empty() || matrix[0].empty()) return 0;
        int m = matrix.size();
        int n = matrix[0].size();
        vector<int> heights(n, 0);
        int maxArea = 0;
        for(int i = 0; i < m; i++){
            for(int j = 0; j < n; j++){
                if(matrix[i][j] == 1) heights[j] += 1;
                else heights[j] = 0;
            }
            maxArea = max(maxArea, largestRectangleArea(heights));
        }
        return maxArea;
    }
};

4-sum.code:
class Solution {
public:
    vector<vector<int>> fourSum(vector<int>& nums, int target) {
        int n = nums.size();
        sort(nums.begin(), nums.end());
        vector<vector<int>> ans;
        for (int a = 0; a < n; a++) {
            if (a > 0 && nums[a] == nums[a - 1]) continue;
            for (int b = a + 1; b < n; b++) {
                if (b > a + 1 && nums[b] == nums[b - 1]) continue;
                int c = b + 1;
                int d = n - 1;
                while (c < d) {
                    long long sum = (long long)nums[a] + nums[b] + nums[c] + nums[d];
                    if (sum == (long long)target) {
                        ans.push_back({nums[a], nums[b], nums[c], nums[d]});
                        c++;
                        d--;
                        while (c < d && nums[c] == nums[c - 1]) c++;
                        while (c < d && nums[d] == nums[d + 1]) d--;
                    } else if (sum < (long long)target) {
                        c++;
                    } else {
                        d--;
                    }
                }
            }
        }
        return ans;
    }
};

kmp-algorithm-or-lps-array.code:
class Solution{
    public:
        vector <int> search(string pat, string txt){
            vector<int> result;
            int n = (int)txt.size(), m = (int)pat.size();
            if (m == 0 || m > n) return result;

            // Build LPS (Longest Proper Prefix which is also Suffix) array for the pattern
            vector<int> lps(m, 0);
            for (int i = 1; i < m; i++) {
                int j = lps[i - 1];
                while (j > 0 && pat[i] != pat[j]) {
                    j = lps[j - 1];
                }
                if (pat[i] == pat[j]) {
                    j++;
                }
                lps[i] = j;
            }

            // KMP search over the text; collect all 0-based starting indices (ascending)
            int j = 0; // number of characters of pat currently matched
            for (int i = 0; i < n; i++) {
                while (j > 0 && txt[i] != pat[j]) {
                    j = lps[j - 1];
                }
                if (txt[i] == pat[j]) {
                    j++;
                }
                if (j == m) {
                    result.push_back(i - m + 1);
                    j = lps[j - 1]; // allow overlapping matches
                }
            }
            return result;
        }
};

best-time-to-buy-and-sell-stock-iv.code:
class Solution{
public:
    int stockBuySell(vector<int> arr, int n, int k){
        // dp[cap][buy]: max profit, buy=0 means we are free to buy, buy=1 means holding a share.
        // Space-optimized iteration over days from last to first.
        vector<vector<int>> ahead(k+1, vector<int>(2, 0));
        vector<vector<int>> cur(k+1, vector<int>(2, 0));
        for(int ind = n-1; ind >= 0; ind--){
            for(int cap = 1; cap <= k; cap++){
                for(int buy = 0; buy <= 1; buy++){
                    int profit;
                    if(buy == 0){ // free to buy
                        profit = max(-arr[ind] + ahead[cap][1], ahead[cap][0]);
                    } else { // holding, may sell (completes a transaction)
                        profit = max(arr[ind] + ahead[cap-1][0], ahead[cap][1]);
                    }
                    cur[cap][buy] = profit;
                }
            }
            ahead = cur;
        }
        return ahead[k][0];
    }
};

minimum-insertions-to-make-string-palind.code:
class Solution{   
public: 
  int minInsertion(string s) {
    int n = s.size();
    string r = s;
    reverse(r.begin(), r.end());
    // LCS of s and reverse(s) == longest palindromic subsequence length
    vector<vector<int>> dp(n + 1, vector<int>(n + 1, 0));
    for (int i = 1; i <= n; i++) {
      for (int j = 1; j <= n; j++) {
        if (s[i - 1] == r[j - 1])
          dp[i][j] = dp[i - 1][j - 1] + 1;
        else
          dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
      }
    }
    int lps = dp[n][n];
    return n - lps;
  }
};

