    int jump(vector<int>& nums) {
        int n = nums.size();
        int jumps = 0;
        int curEnd = 0;
        int farthest = 0;
        for (int i = 0; i < n - 1; i++) {
            farthest = max(farthest, i + nums[i]);
            if (i == curEnd) {
                jumps++;
                curEnd = farthest;
            }
        }
        return jumps;
    }
};

book-allocation-problem.code:
class Solution {
public:
    int findPages(vector<int> &nums, int m)  {
        int n = nums.size();
        if (m > n) return -1;
        long long low = 0, high = 0;
        for (int i = 0; i < n; i++) {
            low = max(low, (long long)nums[i]);
            high += nums[i];
        }
        int ans = -1;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // count minimum students needed if a student may hold at most `mid` pages
            int students = 1;
            long long pagesSum = 0;
            for (int i = 0; i < n; i++) {
                if (pagesSum + nums[i] <= mid) {
                    pagesSum += nums[i];
                } else {
                    students++;
                    pagesSum = nums[i];
                }
            }
            if (students <= m) {
                ans = (int)mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return ans;
    }
};
